 &lt;h2 id=&#34;DAO类&#34;&gt;&lt;a href=&#34;#DAO类&#34; class=&#34;headerlink&#34; title=&#34;DAO类&#34;&gt;&lt;/a&gt;DAO类&lt;/h2&gt;&lt;pre&gt;&lt;code class=&#34;lang-java&#34;&gt;package Dao;
import javax.swing.*;
import java.sql.*;
public class DAO &amp;#123;
    private static final DAO dao = new DAO();
    static &amp;#123;
        try &amp;#123;
            Class.forName(&amp;quot;com.mysql.jdbc.Driver&amp;quot;);
        &amp;#125; catch (ClassNotFoundException e) &amp;#123;
            JOptionPane.showMessageDialog(null, &amp;quot;驱动加载失败&amp;quot;+ e.getMessage());
            e.printStackTrace();
        &amp;#125;
    &amp;#125;
    public static Connection getConn() &amp;#123;
        try &amp;#123;
            Connection conn = null;
            String url = &amp;quot;jdbc:mysql://localhost:3306/news?serverTimezone=UTC&amp;quot;;
            String username = &amp;quot;root&amp;quot;;
            String password = &amp;quot;root&amp;quot;;
            conn = DriverManager.getConnection(url, username, password);
            return conn;
        &amp;#125; catch (Exception e) &amp;#123;
            JOptionPane.showMessageDialog(null,&amp;quot;数据库连接失败!&amp;quot;+ e.getMessage());
            return null;
        &amp;#125;
    &amp;#125;

    public static void main(String[] args) &amp;#123;
        System.out.println(getConn());
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;pom-xml配置&#34;&gt;&lt;a href=&#34;#pom-xml配置&#34; class=&#34;headerlink&#34; title=&#34;pom.xml配置&#34;&gt;&lt;/a&gt;pom.xml配置&lt;/h2&gt;&lt;pre&gt;&lt;code class=&#34;lang-java&#34;&gt;&amp;lt;?xml version=&amp;quot;1.0&amp;quot; encoding=&amp;quot;UTF-8&amp;quot;?&amp;gt;
