&lt;pre&gt;&lt;code class=&#34;lang-java&#34;&gt; String url = &amp;quot;jdbc:mysql://localhost:3306/news?serverTimezone=UTC&amp;quot;;
&lt;/code&gt;&lt;/pre&gt;

 &lt;p&gt;:::info&lt;/p&gt;
