&lt;h2 id=&#34;触发事件&#34;&gt;&lt;a href=&#34;#触发事件&#34; class=&#34;headerlink&#34; title=&#34;触发事件&#34;&gt;&lt;/a&gt;触发事件&lt;/h2&gt;&lt;pre&gt;&lt;code class=&#34;lang-java&#34;&gt;import java.awt.EventQueue;
import javax.swing.JFrame;
