&lt;h3 id=&#34;翻译并命名&#34;&gt;&lt;a href=&#34;#翻译并命名&#34; class=&#34;headerlink&#34; title=&#34;翻译并命名&#34;&gt;&lt;/a&gt;翻译并命名&lt;/h3&gt;&lt;p&gt;&lt;code&gt;ctrl+shift+X&lt;/code&gt;快速命名并填上&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022053617.jpeg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;访问控制&#34;&gt;&lt;a href=&#34;#访问控制&#34; class=&#34;headerlink&#34; title=&#34;访问控制&#34;&gt;&lt;/a&gt;访问控制&lt;/h2&gt;&lt;div class=&#34;table-container&#34;&gt;
