&lt;h2 id=&#34;报错内容-2-red&#34;&gt;&lt;a href=&#34;#报错内容-2-red&#34; class=&#34;headerlink&#34; title=&#34;报错内容~2~{.red}&#34;&gt;&lt;/a&gt;报错内容~2~{.red}&lt;/h2&gt;&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022051525.jpeg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;解决办法-1&#34;&gt;&lt;a href=&#34;#解决办法-1&#34; class=&#34;headerlink&#34; title=&#34;解决办法&#34;&gt;&lt;/a&gt;解决办法&lt;/h3&gt;&lt;p&gt;其实在pom.xml依赖有重复了，删掉就没问题了&lt;/p&gt;
&lt;h2 id=&#34;单元测试成功&#34;&gt;&lt;a href=&#34;#单元测试成功&#34; class=&#34;headerlink&#34; title=&#34;单元测试成功&#34;&gt;&lt;/a&gt;单元测试成功&lt;/h2&gt;&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022051530.jpeg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;函数-1-red&#34;&gt;&lt;a href=&#34;#函数-1-red&#34; class=&#34;headerlink&#34; title=&#34;函数~1~{.red}&#34;&gt;&lt;/a&gt;函数~1~{.red}&lt;/h2&gt;&lt;p&gt;&lt;img data-src=&#34;https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022051002.png&#34; alt=&#34;&#34;&gt;{width=”10%” height=”10%”}&lt;/p&gt;
&lt;p&gt;```python mark:1-10&lt;br&gt;import numpy as np&lt;br&gt;import matplotlib.pyplot as plt&lt;/p&gt;
&lt;p&gt;x = np.arange(-5,5,0.01)    # 设置X的值&lt;br&gt;y = 1/(1+np.exp(-x))         # 设置Y的值，一个Y都有一个X与他对应&lt;br&gt;plt.xlim(-6,6)         #　设置Ｘ轴的范围&lt;br&gt;plt.ylim(0.0,1.0)         # 设置Y轴的范围&lt;br&gt;plt.plot(x,y)             # 将X、Y的值添加到面板中&lt;br&gt;plt.show()             # 显示面板&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;
## 函数~2~&amp;#123;.red&amp;#125;

![](https://cdn.jsdelivr.net/gh/0000rookie/imgs/2022051939.png)&amp;#123;width=&amp;quot;20%&amp;quot; height=&amp;quot;20%&amp;quot;&amp;#125;

```python mark:1-15
import numpy as np
import matplotlib.pyplot as plt

def func(x):
    return np.cos(2*np.pi*x)*np.exp(-x)+1
left_x = int(input(&amp;quot;请输入下限值：&amp;quot;))
right_x = int(input(&amp;quot;请输入上限值：&amp;quot;))
x = np.arange(left_x,right_x,0.01) # 设置X的值
y = func(x)             # 设置Y的值，一个Y都有一个X与他对应
plt.xlim(left_x,right_x)     # 设置X轴的范围
plt.ylim(-15000,25000)             # 设置Y轴的范围
plt.plot(x,y)             # 将X、Y的值添加到面板中
plt.show()            # 显示面板
&lt;/code&gt;&lt;/pre&gt;

 &lt;h2 id=&#34;python散点图&#34;&gt;&lt;a href=&#34;#python散点图&#34; class=&#34;headerlink&#34; title=&#34;python散点图&#34;&gt;&lt;/a&gt;python散点图&lt;/h2&gt;&lt;h3 id=&#34;编写思路&#34;&gt;&lt;a href=&#34;#编写思路&#34; class=&#34;headerlink&#34; title=&#34;编写思路&#34;&gt;&lt;/a&gt;编写思路&lt;/h3&gt;&lt;h4 id=&#34;单个画板思路&#34;&gt;&lt;a href=&#34;#单个画板思路&#34; class=&#34;headerlink&#34; title=&#34;单个画板思路&#34;&gt;&lt;/a&gt;单个画板思路&lt;/h4&gt;&lt;ol&gt;
&lt;li&gt;导入相关模块&lt;/li&gt;
&lt;li&gt;获取数据为列表格式 (这是&lt;code&gt;Y&lt;/code&gt;的值，每一个&lt;code&gt;X&lt;/code&gt;都能找到一个对应的&lt;code&gt;Y&lt;/code&gt;值，称为函数)&lt;/li&gt;
&lt;li&gt;设置颜色(可选)&lt;/li&gt;
&lt;li&gt;添加画板&lt;/li&gt;
&lt;li&gt;设置&lt;code&gt;Ｘ&lt;/code&gt;轴、&lt;code&gt;Ｙ&lt;/code&gt;轴长度&lt;/li&gt;
&lt;li&gt;设置&lt;code&gt;X&lt;/code&gt;的数据&lt;/li&gt;
&lt;li&gt;给画板添加数据&lt;/li&gt;
&lt;li&gt;显示画板&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;多个画板思路&#34;&gt;&lt;a href=&#34;#多个画板思路&#34; class=&#34;headerlink&#34; title=&#34;多个画板思路&#34;&gt;&lt;/a&gt;多个画板思路&lt;/h4&gt;&lt;ol&gt;
&lt;li&gt;&lt;p&gt;导入香相关模块&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;获取&lt;code&gt;lis&lt;/code&gt;数据为列表格式 (这是&lt;code&gt;Y&lt;/code&gt;的值，每一个&lt;code&gt;X&lt;/code&gt;都能找到一个对应的&lt;code&gt;Y&lt;/code&gt;值，称为函数)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;设置颜色(可选)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;添加&lt;code&gt;子图1-子图n&lt;/code&gt;并设置&lt;code&gt;X&lt;/code&gt;、&lt;code&gt;Y&lt;/code&gt;轴长度&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;设置&lt;code&gt;X&lt;/code&gt;的数据&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;添加画板&lt;/p&gt;
&lt;p&gt;```python mark:1-5&lt;br&gt;for i in range(len(lis)):&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;ax1.scatter(x,lis[i],c=colors[i])
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;```&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;展示画板&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;源码&#34;&gt;&lt;a href=&#34;#源码&#34; class=&#34;headerlink&#34; title=&#34;源码&#34;&gt;&lt;/a&gt;源码&lt;/h3&gt;&lt;p&gt;```python mark:1-18&lt;br&gt;import numpy as np&lt;br&gt;import matplotlib.pyplot as plt&lt;/p&gt;
&lt;h1 id=&#34;从data-csv文件读取四列数据，结果返回是一个类似列表的数据，但类型不是列表，可当它是列表使用&#34;&gt;&lt;a href=&#34;#从data-csv文件读取四列数据，结果返回是一个类似列表的数据，但类型不是列表，可当它是列表使用&#34; class=&#34;headerlink&#34; title=&#34;从data.csv文件读取四列数据，结果返回是一个类似列表的数据，但类型不是列表，可当它是列表使用&#34;&gt;&lt;/a&gt;从data.csv文件读取四列数据，结果返回是一个类似列表的数据，但类型不是列表，可当它是列表使用&lt;/h1&gt;&lt;p&gt;opening,top,bottom,closing=np.loadtxt(‘data.csv’, delimiter=’,’, usecols=(3,4,5,6), unpack=True)&lt;/p&gt;
&lt;h1 id=&#34;将数据封装为列表，便于将数据循环添加进画板&#34;&gt;&lt;a href=&#34;#将数据封装为列表，便于将数据循环添加进画板&#34; class=&#34;headerlink&#34; title=&#34;将数据封装为列表，便于将数据循环添加进画板&#34;&gt;&lt;/a&gt;将数据封装为列表，便于将数据循环添加进画板&lt;/h1&gt;&lt;p&gt;lis = [opening,top,bottom,closing]&lt;br&gt;colors = [‘green’,’red’,’b’,’k’]&lt;/p&gt;
&lt;p&gt;fig1 = plt.figure(2)                     # 可有可无&lt;br&gt;ax1 = plt.subplot(211,ylim=(330,370),xlim=(-5,35)) # 添加上子图 211&lt;br&gt;ax2=plt.subplot(212)                 # 添加下子图 212&lt;br&gt;x = np.arange(0,30)                 # 设置x轴&lt;br&gt;for i in range(len(lis)):&lt;br&gt;    ax1.scatter(x,lis[i],c=colors[i]) # 给上子图添加数据&lt;br&gt;    ax2.plot(x,lis[i],c=colors[i]) # 给下子图添加数据&lt;br&gt;plt.show()                     # 展示画板&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;
