```python mark:1-40
import numpy as np
import matplotlib.pyplot as plt

data_y = [112,155,103,72,24,9]
x = [&amp;quot;50分以下&amp;quot;,&amp;quot;50-60分&amp;quot;,&amp;quot;60-70分&amp;quot;,&amp;quot;70-80分&amp;quot;,&amp;quot;80-90分&amp;quot;,&amp;quot;90-100分&amp;quot;]
