&lt;p&gt;data,                                       # 数据&lt;br&gt;labels=x,                                # 数据对应的字段&lt;br&gt;colors=cols,                           # 颜色&lt;br&gt;startangle=180,                    # 旋转角度&lt;br&gt;shadow=    True,                  # 阴影&lt;br&gt;explode=(0,0,0,0,0,0.1),       # 突出某一块，有几个数据就设置几个0或者0.1&lt;br&gt;autopct=’%1.1f%%’)             # 接受特定String，指定数值显示方式，默认为None&lt;/p&gt;
&lt;/li&gt;
