&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;```python mark:1-40&lt;br&gt;import numpy as np&lt;br&gt;import matplotlib.pyplot as plt&lt;/p&gt;
&lt;p&gt;data = [112,155,103,72,24,9]&lt;br&gt;x = [‘50分以下’,’50-60分’,’60-70分’,’70-80分’,’80-90分’,’90-10分’]&lt;br&gt;cols=[‘c’,’m’,’r’,’b’]&lt;/p&gt;
&lt;h1 id=&#34;解决plt中文显示的问题&#34;&gt;&lt;a href=&#34;#解决plt中文显示的问题&#34; class=&#34;headerlink&#34; title=&#34;解决plt中文显示的问题&#34;&gt;&lt;/a&gt;解决plt中文显示的问题&lt;/h1&gt;&lt;p&gt;plt.rcParams[‘font.sans-serif’] = [‘SimHei’]&lt;/p&gt;
&lt;h1 id=&#34;制作饼图&#34;&gt;&lt;a href=&#34;#制作饼图&#34; class=&#34;headerlink&#34; title=&#34;制作饼图&#34;&gt;&lt;/a&gt;制作饼图&lt;/h1&gt;&lt;p&gt;plt.pie(data,# 数据&lt;br&gt;labels=x, # 数据对应的字段&lt;br&gt;colors=cols, # 颜色&lt;br&gt;startangle=180, # 旋转角度&lt;br&gt;shadow=    True, # 阴影&lt;br&gt;explode=(0,0,0,0,0,0.1), # 突出某一块，有几个数据就设置几个0或者0.1&lt;br&gt;autopct=’%1.1f%%’) # 接受特定String，指定数值显示方式，默认为None&lt;/p&gt;
&lt;p&gt;plt.title(‘考试成绩统计’)&lt;br&gt;plt.show()&lt;/p&gt;
